SELECT file_type, COUNT(*) AS count_of_files
FROM incident_files
GROUP BY file_type;

SELECT file_name, file_type
FROM incident_files
WHERE file_type = 'image/jpeg';

SELECT incident_severity_name, incident_severity_description
FROM incident_severity
WHERE incident_severity_id <= 1;

SELECT incident_severity_description
FROM incident_severity
WHERE incident_severity_id = 1;

SELECT user_id, COUNT(incident_comment_id) AS comment_count
FROM incident_comments
GROUP BY user_id;

SELECT COUNT(*) AS non_violent_crime_count
FROM incident_categories
WHERE incident_category_name = 'Non-Violent Crime';
